+.stage {
+  height: 100dvh;
+  width: 100%;
+  display: flex;
+  justify-content: center;
+  background:
+    radial-gradient(120% 80% at 50% -10%, #14171f 0%, #0b0d11 55%, #08090c 100%),
+    #0b0d11;
+  color: #f4efe4;
+  overflow: hidden;
+}
+
+.phone {
+  position: relative;
+  width: 100%;
+  max-width: 440px;
+  height: 100dvh;
+  padding: max(30px, env(safe-area-inset-top)) 26px max(26px, env(safe-area-inset-bottom));
+  isolation: isolate;
+  overflow: hidden;
+}
+
+@media (min-width: 640px) {
+  .stage {
+    align-items: center;
+    padding: 3vh 0;
+  }
+
+  .phone {
+    height: min(920px, 94vh);
+    border: 1px solid rgba(255, 255, 255, 0.06);
+    border-radius: 42px;
+    box-shadow: 0 50px 120px -30px rgba(0, 0, 0, 0.9);
+  }
+}
+
+.phone::before {
+  content: '';
+  position: absolute;
+  inset: 0;
+  z-index: -2;
+  background:
+    radial-gradient(70% 50% at 80% 0%, rgba(216, 178, 106, 0.1), transparent 60%),
