+'use client'
+
+import { useState } from 'react'
+
+import { Button } from '@/components/ds/button'
+import { sendSmsOTP } from '@/lib/auth/api'
+import { authManager } from '@/lib/auth/manager'
+
+import styles from '../bossclaw.module.css'
+
+// SMS OTP via Aliyun (account-service /auth/sms/*): the code is generated,
+// stored, and validated server-side, so this step needs no Firebase, no
+// Turnstile, and no captcha channel — the browser only talks to our backend.
+export default function PhoneLoginStep({ onNext }: { onNext: () => void }) {
+  const [phone, setPhone] = useState('')
+  const [code, setCode] = useState('')
+  const [codeSent, setCodeSent] = useState(false)
+  const [error, setError] = useState('')
+  const [busy, setBusy] = useState(false)
+
+  const phoneValid = /^1\d{10}$/.test(phone)
+
+  const handleSend = async () => {
+    setError('')
+    setBusy(true)
+    try {
+      await sendSmsOTP(`+86${phone}`)
+      setCodeSent(true)
+    } catch (err) {
+      const message = err instanceof Error && err.message ? err.message : ''
+      setError(message ? `短信发送失败：${message}` : '短信发送失败，请稍后重试')
+    } finally {
+      setBusy(false)
+    }
+  }
+
+  const handleVerify = async () => {
+    setError('')
+    setBusy(true)
+    try {
+      const result = await authManager.loginWithSmsOTP(`+86${phone}`, code)
+      if (!result.uid) {
+        setError('登录状态同步失败，请重新登录')
+        return
+      }
+      onNext()
+    } catch (err) {
+      const message = err instanceof Error && err.message ? err.message : ''
+      setError(message ? `登录失败：${message}` : '验证码错误，请重新输入')
+    } finally {
+      setBusy(false)
+    }
+  }
+
+  return (
+    <section className={styles.stack}>
+      {!codeSent ? (
+        <>
+          <div className={styles.field}>
+            <span className={styles.prefix}>+86</span>
+            <input
+              className={styles.input}
+              inputMode="numeric"
+              maxLength={11}
+              placeholder="请输入手机号"
+              value={phone}
+              onChange={(e) => setPhone(e.target.value.replace(/\D/g, ''))}
+            />
+          </div>
+          <Button className={styles.primaryButton} disabled={!phoneValid || busy} size="lg" onClick={handleSend}>
+            {busy ? '发送中…' : '获取验证码'}
+          </Button>
+        </>
+      ) : (
+        <>
+          <p className={styles.hint}>验证码已发送至 +86 {phone}</p>
+          <input
+            className={styles.otpInput}
+            inputMode="numeric"
+            maxLength={6}
+            placeholder="6 位验证码"
+            value={code}
+            onChange={(e) => setCode(e.target.value.replace(/\D/g, ''))}
+          />
+          <Button
+            className={styles.primaryButton}
+            disabled={code.length !== 6 || busy}
+            size="lg"
+            onClick={handleVerify}
+          >
+            {busy ? '验证中…' : '登录'}
+          </Button>
+          <Button className={styles.secondaryButton} size="sm" variant="ghost" onClick={() => setCodeSent(false)}>
+            重新输入手机号
+          </Button>
+        </>
+      )}
+      {error ? <p className={styles.error}>{error}</p> : null}
+    </section>
+  )
+}

