+export type WizardStep = 'intro' | 'capabilities' | 'login' | 'redeem' | 'wechat' | 'done'
+
+const STEP_STORAGE_KEY = 'bossclaw:step'
+const STEP_TTL_MS = 10 * 60 * 1000
+export const STEP_ORDER: WizardStep[] = ['intro', 'capabilities', 'login', 'redeem', 'wechat', 'done']
+const POST_LOGIN_STEPS: WizardStep[] = ['redeem', 'wechat', 'done']
+
+interface StoredStep {
+  step: WizardStep
+  expiresAt: number
+}
+
+export function getBossclawStepKey(uid: string): string {
+  return `${STEP_STORAGE_KEY}:${uid}`
+}
+
+function isPostLoginStep(value: string): value is WizardStep {
+  return POST_LOGIN_STEPS.includes(value as WizardStep)
+}
+
+export function createBossclawStepPayload(step: WizardStep, now = Date.now()): string {
+  return JSON.stringify({
+    step,
+    expiresAt: now + STEP_TTL_MS,
+  } satisfies StoredStep)
+}
+
+export function parseBossclawStep(raw: string | null, now = Date.now()): WizardStep | null {
+  if (!raw) return null
+
+  if (isPostLoginStep(raw)) {
+    return raw
+  }
+
+  try {
+    const parsed = JSON.parse(raw) as Partial<StoredStep>
+    if (!parsed.step || !isPostLoginStep(parsed.step)) return null
+    if (typeof parsed.expiresAt !== 'number' || parsed.expiresAt <= now) return null
+    return parsed.step
+  } catch {
+    return null
+  }
+}
+
+export function readBossclawStep(uid: string, now = Date.now()): WizardStep | null {
+  const key = getBossclawStepKey(uid)
+  const raw = localStorage.getItem(key)
+  const step = parseBossclawStep(raw, now)
+
+  if (!step) {
+    localStorage.removeItem(key)
+    return null
+  }
+
+  if (raw === step) {
+    localStorage.setItem(key, createBossclawStepPayload(step, now))
+  }
+
+  return step
+}
+
+export function saveBossclawStep(uid: string, step: WizardStep, now = Date.now()): void {
+  localStorage.setItem(getBossclawStepKey(uid), createBossclawStepPayload(step, now))
+}
+
+// Pure resume rule: a saved step only counts after authenticated phone login.
+export function resolveInitialStep(loggedIn: boolean, savedStep: string | null): WizardStep {
+  if (!loggedIn) return 'intro'
+  const parsedStep = parseBossclawStep(savedStep)
+  if (parsedStep) {
+    return parsedStep
+  }
+  return 'redeem'
+}

