+import type { CachedAgentIdentity, CachedGlobalIdentity } from '@/hooks/useNavIdentity'
+import type { AgentInfo } from '@/lib/api/openclaw'
+import { resolveChatIdentity } from '@/lib/chat/chat-identity'
+import { getAgentAnimal, getAgentAvatarUrl, getAgentDisplayName } from '@/lib/use-cases'
+
+export type NewChatAgentAvatar =
+  | { kind: 'image'; src: string }
+  | { kind: 'animal'; animalId: string; avatarUrl?: string }
+  | { kind: 'emoji'; emoji: string }
+
+interface MainAgentIdentity {
+  name: string
+  avatar?: string
+}
+
+export interface NewChatAgentPresentation {
+  displayName: string
+  avatar: NewChatAgentAvatar
+}
+
+function normalizeUrl(value?: string | null): string | undefined {
+  if (typeof value !== 'string') return undefined
+  const normalized = value.trim()
+  return normalized.length > 0 ? normalized : undefined
+}
+
+export function resolveNewChatAgentPresentation({
+  agent,
+  mainAgentIdentity,
+  globalIdentity,
+  agentIdentityMap,
+}: {
+  agent: AgentInfo
+  mainAgentIdentity?: MainAgentIdentity
+  globalIdentity: CachedGlobalIdentity
+  agentIdentityMap: Record<string, CachedAgentIdentity>
+}): NewChatAgentPresentation {
+  if (agent.isDefault) {
+    return {
+      displayName: mainAgentIdentity?.name ?? 'Assistant',
+      avatar: mainAgentIdentity?.avatar
+        ? { kind: 'image', src: mainAgentIdentity.avatar }
+        : { kind: 'emoji', emoji: agent.emoji },
+    }
+  }
+
+  const resolved = resolveChatIdentity({
+    agentId: agent.id,
+    activeAgent: agent,
+    globalIdentity,
+    agentSettings: agentIdentityMap[agent.id] ?? null,
+    fallbackName: getAgentDisplayName(agent.id, agent.name),
+  })
+  const animalId = getAgentAnimal(agent.id)
+  const workspaceAvatarUrl = normalizeUrl(agent.avatar_url)
+
+  if (workspaceAvatarUrl) {
+    return {
+      displayName: resolved.name,
+      avatar: { kind: 'animal', animalId: animalId ?? agent.id, avatarUrl: workspaceAvatarUrl },
+    }
+  }
+
+  if (resolved.avatar) {
+    return {
+      displayName: resolved.name,
+      avatar: { kind: 'image', src: resolved.avatar },
+    }
+  }
+
+  if (animalId) {
+    return {
+      displayName: resolved.name,
+      avatar: { kind: 'animal', animalId, avatarUrl: getAgentAvatarUrl(agent.id) },
+    }
+  }
+
+  return {
+    displayName: resolved.name,
+    avatar: { kind: 'emoji', emoji: agent.emoji },
+  }
+}
+
+export function getNewChatAgentAnimalId(presentation: NewChatAgentPresentation | null): string | undefined {
+  return presentation?.avatar.kind === 'animal' ? presentation.avatar.animalId : undefined
+}
+
+export function getNewChatAgentAvatarUrl(presentation: NewChatAgentPresentation | null): string | undefined {
+  if (!presentation) return undefined
+  if (presentation.avatar.kind === 'image') return presentation.avatar.src
+  if (presentation.avatar.kind === 'animal') return presentation.avatar.avatarUrl
+  return undefined
+}

