+				const active = l.id === lang;
+				return (
+					<button
+						key={l.id}
+						type="button"
+						onClick={() => setLang(l.id)}
+						aria-pressed={active}
+						title={l.name}
+						className={cn(
+							"rounded-[5px] px-2 py-0.5 font-mono text-[10px] font-bold uppercase tracking-[0.14em] transition-colors",
+							active
+								? "bg-zc-ink text-white"
+								: "text-zc-text-3 hover:text-zc-text",
+						)}
+					>
+						{l.label}
+					</button>
+				);
+			})}
+		</div>
+	);
+}

