+import { render, screen } from "@testing-library/react";
+import { describe, expect, it } from "vitest";
+
+import { ZooClawWordmark } from "@/components/Brand";
+
+// The auth surfaces pin themselves light and therefore render a fixed logo
+// path instead of the system-tracking <picture>. These tests lock that
+// behavior (flagged as uncovered in Codex review of PR #2473).
+describe("ZooClawWordmark", () => {
+	it("theme=light renders the black logotype with no system-tracking <picture>", () => {
+		const { container } = render(<ZooClawWordmark theme="light" />);
+		const img = screen.getByAltText("ZooClaw");
+		expect(img.getAttribute("src")).toBe("/brand/zooclaw-logo-black.svg");
+		expect(container.querySelector("picture")).toBeNull();
+		expect(container.querySelector("source")).toBeNull();
+	});
+
+	it("theme=dark renders the white logotype with no <picture>", () => {
+		const { container } = render(<ZooClawWordmark theme="dark" />);
+		const img = screen.getByAltText("ZooClaw");
+		expect(img.getAttribute("src")).toBe("/brand/zooclaw-logo-white.svg");
+		expect(container.querySelector("picture")).toBeNull();
+	});
+
+	it("theme=auto (default) art-directs via <picture> tracking the system scheme", () => {
+		const { container } = render(<ZooClawWordmark />);
+		expect(container.querySelector("picture")).not.toBeNull();
+		const source = container.querySelector("source");
+		expect(source?.getAttribute("media")).toBe("(prefers-color-scheme: dark)");
+		expect(source?.getAttribute("srcset")).toBe(
+			"/brand/zooclaw-logo-white.svg",
+		);
+		// Fallback <img> stays the black mark for light surfaces.
+		expect(screen.getByAltText("ZooClaw").getAttribute("src")).toBe(
+			"/brand/zooclaw-logo-black.svg",
+		);
+	});
+
+	it("applies the requested height", () => {
+		render(<ZooClawWordmark theme="light" height={22} />);
+		expect(screen.getByAltText("ZooClaw").style.height).toBe("22px");
+	});
+});

