@@ -0,0 +1,60 @@
+// Six-cell one-time-code input: a visual grid of digits with an underline that
+// fills (red) as the user types, backed by a single transparent <input> overlay.
+// Shared by the /verify and /join screens.
+export function OtpGrid({
+	id,
+	value,
+	onChange,
+	error,
+}: {
+	id: string;
+	value: string;
+	onChange: (next: string) => void;
+	error?: boolean;
+}) {
+	const filled = value.length;
+	return (
+		<div className="relative">
+			<div aria-hidden className="grid grid-cols-6 gap-2">
+				{Array.from({ length: 6 }).map((_, i) => {
+					const char = value[i] ?? "";
+					const isNext = i === filled && filled < 6;
+					return (
+						<div key={i} className="flex flex-col items-stretch">
+							<div className="flex h-14 items-center justify-center font-mono text-2xl tabular-nums text-zc-text md:text-3xl">
+								{char ||
+									(isNext ? (
+										<span className="block h-7 w-px animate-pulse bg-zc-text/70" />
+									) : (
+										<span className="text-zc-text-3/40">0</span>
+									))}
+							</div>
+							<span
+								className={`h-0.5 w-full rounded-full transition-colors duration-300 ${
+									i < filled
+										? "bg-zc-red"
+										: isNext
+											? "bg-zc-text/40"
+											: "bg-zc-line-strong"
+								}`}
+							/>
+						</div>
+					);
+				})}
+			</div>
+			<input
+				id={id}
+				inputMode="numeric"
+				autoComplete="one-time-code"
+				pattern="[0-9]{6}"
+				maxLength={6}
+				value={value}
+				onChange={(e) => onChange(e.target.value)}
+				required
+				autoFocus
+				aria-invalid={error ? true : undefined}
+				className="absolute inset-0 h-full w-full cursor-text bg-transparent p-0 text-transparent caret-transparent outline-none selection:bg-transparent"
+			/>
+		</div>
+	);
+}

