+import { fireEvent, render, screen } from "@testing-library/react";
+import { describe, expect, it, vi } from "vitest";
+
+import { FileField } from "@/components/ui/file-field";
+
+function pick(input: Element, name: string) {
+	const file = new File(["x"], name, { type: "application/zip" });
+	fireEvent.change(input, { target: { files: [file] } });
+}
+
+describe("FileField", () => {
+	it("uncontrolled: shows the picked file name", () => {
+		const { container } = render(
+			<FileField placeholder="Pack archive (.zip)" onChange={vi.fn()} />,
+		);
+		const input = container.querySelector('input[type="file"]')!;
+		pick(input, "good.zip");
+		expect(screen.getByText("good.zip")).toBeInTheDocument();
+	});
+
+	it("controlled: a rejected selection (selectedName=null) keeps the placeholder", () => {
+		// The caller validates onChange, rejects the file, and clears its state.
+		// selectedName=null must override the just-picked name so a rejected file
+		// is never shown as accepted.
+		const onChange = vi.fn();
+		const { container } = render(
+			<FileField
+				placeholder="Pack archive (.zip)"
+				selectedName={null}
+				onChange={onChange}
+			/>,
+		);
+		const input = container.querySelector('input[type="file"]')!;
+		pick(input, "not-a-zip.txt");
+		expect(onChange).toHaveBeenCalled();
+		expect(screen.getByText("Pack archive (.zip)")).toBeInTheDocument();
+		expect(screen.queryByText("not-a-zip.txt")).not.toBeInTheDocument();
+	});
+
+	it("resets the native input value so the same file can be re-picked", () => {
+		// Browsers don't re-fire `change` for an unchanged input value, so after a
+		// rejection the input must be cleared or re-selecting the same file is a
+		// dead end. The label stays driven by selectedName, not the input value.
+		const { container } = render(
+			<FileField selectedName={null} onChange={vi.fn()} />,
+		);
+		const input = container.querySelector(
+			'input[type="file"]',
+		) as HTMLInputElement;
+		pick(input, "rejected.zip");
+		expect(input.value).toBe("");
+	});
+
+	it("controlled: shows the accepted file name from selectedName", () => {
+		render(
+			<FileField
+				placeholder="Pack archive (.zip)"
+				selectedName="accepted.zip"
+				onChange={vi.fn()}
+			/>,
+		);
+		expect(screen.getByText("accepted.zip")).toBeInTheDocument();
+	});
+});

