+"use client";
+
+import { Upload } from "lucide-react";
+import { useId, useRef, useState } from "react";
+
+import { cn } from "@/lib/utils";
+
+// Styled file picker — hides the unpolished native control behind a clean
+// "Choose file" button plus a filename label. Forwards the raw change event so
+// callers keep their existing validation/upload logic.
+//
+// Pass `selectedName` to drive the label from the caller's *validated* state
+// (controlled mode): when the caller rejects a selection and clears its file,
+// the label must clear too, otherwise a rejected file looks accepted. Omit it
+// for simple uncontrolled use (the label tracks the last picked file name).
+export function FileField({
+	id,
+	accept,
+	disabled,
+	required,
+	placeholder = "No file selected",
+	buttonLabel = "Choose file",
+	selectedName,
+	onChange,
+	className,
+}: {
+	id?: string;
+	accept?: string;
+	disabled?: boolean;
+	required?: boolean;
+	placeholder?: string;
+	buttonLabel?: string;
+	selectedName?: string | null;
+	onChange: (event: React.ChangeEvent<HTMLInputElement>) => void;
+	className?: string;
+}) {
+	const ref = useRef<HTMLInputElement>(null);
+	const fallbackId = useId();
+	const inputId = id ?? fallbackId;
+	const [fileName, setFileName] = useState<string | null>(null);
+	// Controlled when `selectedName` is provided (even as null); else fall back to
+	// the internally-tracked last-picked name.
+	const displayName = selectedName !== undefined ? selectedName : fileName;
+
+	return (
+		<div
+			className={cn(
+				"flex items-center gap-3 rounded-lg border border-zc-line bg-zc-paper p-1.5 pr-3.5 transition-colors focus-within:border-zc-red/50 focus-within:ring-2 focus-within:ring-zc-red/15",
+				disabled && "opacity-60",
+				className,
+			)}
+		>
+			<button
+				type="button"
+				disabled={disabled}
+				onClick={() => ref.current?.click()}
+				className="inline-flex shrink-0 items-center gap-1.5 rounded-md bg-zc-ink px-3 py-1.5 text-[12.5px] font-semibold text-white transition-colors hover:bg-zc-ink-800 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-zc-red/40 disabled:cursor-not-allowed"
+			>
+				<Upload aria-hidden className="size-3.5" />
+				{buttonLabel}
+			</button>
+			<span className={cn("min-w-0 flex-1 truncate text-[13px]", displayName ? "text-zc-text" : "text-zc-text-3")}>
+				{displayName ?? placeholder}
+			</span>
+			<input
+				ref={ref}
+				id={inputId}
+				type="file"
+				accept={accept}
+				required={required}
+				disabled={disabled}
+				className="sr-only"
+				onChange={(event) => {
+					setFileName(event.target.files?.[0]?.name ?? null);
+					onChange(event);
+					// Clear the native value once the caller has read the selection, so
+					// re-picking the SAME file fires `change` again. Without this, a user
+					// who re-selects a just-rejected file gets no second callback (the
+					// browser de-dupes unchanged input values). The visible label is
+					// driven by `selectedName`/`fileName`, not the input value, so this
+					// doesn't blank the display.
+					event.target.value = "";
+				}}
+			/>
+		</div>
+	);
+}

