+// Human-readable date formatting for the admin console. Backend timestamps are
+// ISO 8601 strings (e.g. "2026-06-09T10:24:00Z"); raw ISO reads as developer
+// output, so surface a clean label instead. Falls back to the raw value when the
+// input can't be parsed.
+//
+// timeZone is pinned to UTC so the value is identical on the server and the
+// client: these components prerender on the server, and a viewer-local formatter
+// (Intl's default) would format in the server TZ during SSR and re-format in the
+// browser TZ on hydration, causing hydration mismatches / visible timestamp
+// jumps near day boundaries. UTC is also the unambiguous choice for the
+// audit-style timestamps shown here (submission / review times).
+
+const DATE_FMT = new Intl.DateTimeFormat("en-US", {
+	year: "numeric",
+	month: "short",
+	day: "numeric",
+	timeZone: "UTC",
+});
+
+const DATE_TIME_FMT = new Intl.DateTimeFormat("en-US", {
+	year: "numeric",
+	month: "short",
+	day: "numeric",
+	hour: "2-digit",
+	minute: "2-digit",
+	timeZone: "UTC",
+	// Show the zone so a non-UTC operator doesn't read the time as their own wall
+	// clock (e.g. "Jun 9, 2026, 06:24 PM UTC").
+	timeZoneName: "short",
+});
+
+function parse(value: string | null | undefined): Date | null {
+	if (!value) return null;
+	const date = new Date(value);
+	return Number.isNaN(date.getTime()) ? null : date;
+}
+
+/** "2026-06-09T10:24:00Z" → "Jun 9, 2026" */
+export function formatDate(value: string | null | undefined): string {
+	const date = parse(value);
+	return date ? DATE_FMT.format(date) : (value ?? "—");
+}
+
+/** "2026-06-09T10:24:00Z" → "Jun 9, 2026, 10:24 AM UTC" */
+export function formatDateTime(value: string | null | undefined): string {
+	const date = parse(value);
+	return date ? DATE_TIME_FMT.format(date) : (value ?? "—");
+}

