+"use client";
+/*
+ * Lightweight, incremental-friendly i18n for the ZooClaw Business admin console.
+ *
+ * Ported from web/enterprise-app's `lib/i18n.tsx` (the design source of truth) so
+ * the admin follows the same pattern instead of web/app's heavier `[locale]`
+ * routing. No URL routing, no middleware — language lives in React context and is
+ * persisted to localStorage, so the toggle is global.
+ *
+ * Resolution order of `t(key, fallback)`: current lang → English catalog →
+ * call-site fallback → key. English copy stays inline at every call site as the
+ * `fallback`, so:
+ *   - nothing ever renders a raw key,
+ *   - English remains the de-facto source of truth (CATALOG.en stays empty), and
+ *   - a missing zh key silently shows English (incremental-safe migration).
+ */
+import {
+	createContext,
+	useCallback,
+	useContext,
+	useMemo,
+	useSyncExternalStore,
+	type ReactNode,
+} from "react";
+
+import { CATALOG_ZH } from "./i18n-zh";
+
+export type LangId = "en" | "zh";
+
+export interface Lang {
+	id: LangId;
+	label: string;
+	name: string;
+}
+
+export const LANGS: Lang[] = [
+	{ id: "en", label: "EN", name: "English" },
+	{ id: "zh", label: "中", name: "中文" },
+];
+
+// CATALOG.en is intentionally empty — the English strings live inline as the
+// `t(key, "English")` fallbacks. Only zh needs a catalog.
+const CATALOG: Record<LangId, Record<string, string>> = {
+	en: {},
+	zh: CATALOG_ZH,
+};
+
+const STORAGE_KEY = "zooclaw.admin.lang";
+
+function isLangId(value: string | null): value is LangId {
+	return value === "en" || value === "zh";
+}
+
+// `lang` is backed by localStorage via useSyncExternalStore — the React-built-in
+// way to read an external store without an SSR hydration mismatch (the server
+// snapshot is always "en"; the client reconciles to the saved value after
+// hydration) and without a setState-in-effect. Same-tab writes notify via the
+// listener set; cross-tab changes arrive on the "storage" event.
+const langListeners = new Set<() => void>();
+
+function readStoredLang(): LangId {
+	try {
+		const saved = localStorage.getItem(STORAGE_KEY);
+		if (isLangId(saved)) return saved;
+	} catch {
+		/* ignore */
+	}
+	return "en";
+}
+
+function subscribeLang(onChange: () => void): () => void {
+	langListeners.add(onChange);
+	if (typeof window !== "undefined") {
+		window.addEventListener("storage", onChange);
+	}
+	return () => {
+		langListeners.delete(onChange);
+		if (typeof window !== "undefined") {
+			window.removeEventListener("storage", onChange);
+		}
+	};
+}
+
+function writeStoredLang(l: LangId): void {
+	try {
+		localStorage.setItem(STORAGE_KEY, l);
+	} catch {
+		/* ignore */
+	}
+	langListeners.forEach((cb) => cb());
+}
+
+export type TParams = Record<string, string | number>;
+
+export interface LangContextValue {
+	lang: LangId;
+	setLang: (l: LangId) => void;
+	t: (key: string, fallback?: string, params?: TParams) => string;
+}
+
+// Substitutes `{name}` tokens in a resolved string. Keeps interpolation in one
+// place so counts/plurals read naturally in both languages
+// (e.g. "Step {n} / {total}" / "第 {n} / {total} 步").
+function interpolate(template: string, params?: TParams): string {
+	if (!params) return template;
+	return template.replace(/\{(\w+)\}/g, (match, name: string) =>
+		name in params ? String(params[name]) : match,
+	);
+}
+
+const LangContext = createContext<LangContextValue>({
+	lang: "en",
+	setLang: () => {},
+	t: (k, fb, params) => interpolate(fb ?? k, params),
+});
+
+export function LangProvider({ children }: { children: ReactNode }) {
+	// Server snapshot is always "en" (no hydration mismatch); the client settles
+	// to the saved value after hydration.
+	const lang = useSyncExternalStore<LangId>(
+		subscribeLang,
+		readStoredLang,
+		() => "en",
+	);
+
+	const setLang = useCallback((l: LangId) => writeStoredLang(l), []);
+
+	const t = useCallback(
+		(key: string, fallback?: string, params?: TParams) => {
+			const cur = CATALOG[lang]?.[key];
+			if (cur != null) return interpolate(cur, params);
+			const en = CATALOG.en[key];
+			if (en != null) return interpolate(en, params);
+			return interpolate(fallback != null ? fallback : key, params);
+		},
+		[lang],
+	);
+
+	const value = useMemo<LangContextValue>(
+		() => ({ lang, setLang, t }),
+		[lang, setLang, t],
+	);
+
+	return <LangContext.Provider value={value}>{children}</LangContext.Provider>;
+}
+
+export const useLang = () => useContext(LangContext);

