+#!/usr/bin/env node
+// Remove dangling symlinks under a directory tree.
+//
+// Next's standalone tracer leaves a few broken pnpm dev-dependency links
+// behind (e.g. `node_modules/shiki`, `node_modules/typescript`). When
+// `stage-web` copies the standalone output with `rsync -L` (follow symlinks),
+// rsync tries to dereference those dangling links and aborts the whole copy
+// with exit code 23. Pruning them first keeps the copy clean. Pure Node so it
+// also works on the Windows CI runner (no `find`/`rsync` assumptions).
+const fs = require('fs')
+const path = require('path')
+
+const root = process.argv[2]
+if (!root) {
+  console.error('usage: prune-broken-symlinks.js <dir>')
+  process.exit(1)
+}
+
+let removed = 0
+function walk(dir) {
+  let entries
+  try {
+    entries = fs.readdirSync(dir, { withFileTypes: true })
+  } catch {
+    return
+  }
+  for (const entry of entries) {
+    const full = path.join(dir, entry.name)
+    if (entry.isSymbolicLink()) {
+      try {
+        fs.statSync(full) // follows the link; throws if the target is missing
+      } catch {
+        fs.rmSync(full, { force: true })
+        removed++
+      }
+    } else if (entry.isDirectory()) {
+      walk(full)
+    }
+  }
+}
+
+walk(path.resolve(root))
+console.log(`prune-broken-symlinks: removed ${removed} dangling link(s) under ${root}`)

