+import { render, screen } from "@testing-library/react";
+import { beforeEach, describe, expect, it, vi } from "vitest";
+
+import { MobileNav } from "@/components/layout/MobileNav";
+import { Sidebar, WEB_APP_URL } from "@/components/layout/Sidebar";
+
+const usePathnameMock = vi.fn();
+
+vi.mock("next/navigation", () => ({
+	usePathname: () => usePathnameMock(),
+}));
+
+vi.mock("@/hooks/useAuth", () => ({
+	useAuth: () => ({
+		user: { email: "admin@acme.test" },
+		org: { name: "Acme" },
+	}),
+}));
+
+describe("Sidebar", () => {
+	beforeEach(() => {
+		usePathnameMock.mockReturnValue("/users");
+	});
+
+	it("renders an entry that jumps to the web app new chat", () => {
+		render(<Sidebar role="admin" />);
+
+		const link = screen.getByRole("link", { name: /web app/i });
+		expect(link).toHaveAttribute("href", WEB_APP_URL);
+		expect(WEB_APP_URL).toBe("https://zooclaw.ai/new-chat");
+	});
+});
+
+describe("MobileNav", () => {
+	beforeEach(() => {
+		usePathnameMock.mockReturnValue("/users");
+	});
+
+	it("renders the web app entry as an external non-active link", () => {
+		render(<MobileNav role="admin" />);
+
+		const link = screen.getByRole("link", { name: /web app/i });
+		expect(link).toHaveAttribute("href", WEB_APP_URL);
+		expect(link).not.toHaveClass("bg-zc-canvas");
+	});
+});

