+
+    expect(result.current.searchQuery).toBe("");
+    expect(result.current.visiblePlans.map((p) => p.plan_id)).toEqual([
+      "plan_edited_recently", // updated 06-10 leads despite the earlier created_at
+      "plan_recently_created", // updated 06-06
+    ]);
+  });
+
+  it("matches the query across plan dimensions", () => {
+    const { result } = renderVm();
+
+    // Plan name.
+    act(() => result.current.setSearchQuery("launch"));
+    expect(result.current.visiblePlans.map((plan) => plan.plan_id)).toEqual([
+      "plan_launch_ops",
+    ]);
+
+    // An add-on agent id carried only by Lifestyle, case-insensitive.
+    act(() => result.current.setSearchQuery("PACK_TAROT"));
+    expect(result.current.visiblePlans.map((plan) => plan.plan_id)).toEqual([
+      "plan_lifestyle",
+    ]);
+
+    // Price.
+    act(() => result.current.setSearchQuery("29"));
+    expect(result.current.visiblePlans.map((plan) => plan.plan_id)).toEqual([
+      "plan_launch_ops",
+    ]);
+
+    // No match.
+    act(() => result.current.setSearchQuery("no-such-plan"));
+    expect(result.current.visiblePlans).toHaveLength(0);
+  });
+
+  it("finds plans by their agents' display names, not just pack ids", () => {
+    // With the pack catalogue supplied, the table-visible names are searchable.
+    const { result } = renderVm([...INITIAL_ZOOCLAW_PACKS]);
+
+    // "Agent Studio" is the display name of pack_agent_studio, included in Launch Ops.
+    act(() => result.current.setSearchQuery("agent studio"));
+    expect(result.current.visiblePlans.map((p) => p.plan_id)).toEqual([
+      "plan_launch_ops",
+    ]);
+
+    // "Zoo Buddy" (pack_zoo_buddy) is shared — an add-on on Launch Ops and an
+    // included agent on Lifestyle — so it matches both, newest-updated first.
+    act(() => result.current.setSearchQuery("zoo buddy"));
+    expect(result.current.visiblePlans.map((p) => p.plan_id)).toEqual([
+      "plan_lifestyle", // updated 10:00
+      "plan_launch_ops", // updated 09:00
+    ]);
+
+    // "Tarot" is an add-on pack on Lifestyle — add-ons are searchable by name too.
+    act(() => result.current.setSearchQuery("tarot"));
+    expect(result.current.visiblePlans.map((p) => p.plan_id)).toEqual([
+      "plan_lifestyle",
+    ]);
+
+    // The raw pack id still works.
+    act(() => result.current.setSearchQuery("pack_agent_studio"));
+    expect(result.current.visiblePlans.map((p) => p.plan_id)).toEqual([
+      "plan_launch_ops",
+    ]);
+  });
+});

