+function filterAndSortPlans(
+  plans: VerticalPackPlan[],
+  searchQuery: string,
+  packs: readonly Pack[],
+): VerticalPackPlan[] {
+  const query = searchQuery.trim().toLowerCase();
+  return plans
+    .filter((plan) => !query || planMatchesQuery(plan, query, packs))
+    .sort(compareUpdatedDesc);
+}
+
+// Match the query against the plan's own fields (name, id, price, credits) plus,
+// for each included and add-on agent pack, BOTH its raw id and its resolved
+// display name. Operators see pack names like "Agent Studio" in the table, so a
+// name search must hit even though the underlying value is a hidden pack_* id.
+function planMatchesQuery(
+  plan: VerticalPackPlan,
+  query: string,
+  packs: readonly Pack[],
+): boolean {
+  const agentIds = [
+    ...plan.agents,
+    ...plan.addon_agents.map((addon) => addon.agent_pack_id),
+  ];
+  const fields = [
+    plan.name,
+    plan.plan_id,
+    plan.price,
+    plan.credits,
+    ...agentIds,
+    ...agentIds.map((id) => resolvePackLabel(packs, id)),
+  ];
+  return fields.some(
+    (field) => field != null && field.toLowerCase().includes(query),
+  );
+}
+
+// Most recently updated first, so a just-edited plan surfaces at the top (edits
+// bump updated_at; created_at would leave it stuck behind older, untouched
+// plans). ISO-8601 sorts lexicographically in chronological order, so a reversed
+// string compare is enough. Entries without a timestamp sink to the bottom.
+function compareUpdatedDesc(a: VerticalPackPlan, b: VerticalPackPlan): number {
+  const left = a.updated_at ?? "";
+  const right = b.updated_at ?? "";
+  if (left === right) return 0;
+  if (!left) return 1;
+  if (!right) return -1;
+  return right.localeCompare(left);
+}

